<?php include 'includes/config.php'; require_role('seller'); $u=current_user();$stmt=$pdo->prepare('SELECT * FROM seller_payment_details WHERE seller_id=?');$stmt->execute([$u['id']]);$pay=$stmt->fetch(PDO::FETCH_ASSOC);
if($_SERVER['REQUEST_METHOD']==='POST'){$bank=clean($_POST['bank_name']);$holder=clean($_POST['account_holder']);$acc=clean($_POST['account_number']); if($pay){$pdo->prepare('UPDATE seller_payment_details SET bank_name=?,account_holder=?,account_number=? WHERE seller_id=?')->execute([$bank,$holder,$acc,$u['id']]);}else{$pdo->prepare('INSERT INTO seller_payment_details(seller_id,bank_name,account_holder,account_number) VALUES(?,?,?,?)')->execute([$u['id'],$bank,$holder,$acc]);} header('Location: seller-dashboard.php');exit;}
?><!DOCTYPE html><html><head><title>Payment Details</title><link rel="stylesheet" href="css/styles.css"></head><body><?php include 'includes/header.php'; ?><form class="form-shell" method="post"><h1>Seller Payment Details</h1><p class="muted">These details are only used for buyers to pay you during checkout. Admin dashboard does not display account numbers.</p><br><div class="field"><label>Bank Name</label><input name="bank_name" value="<?= clean($pay['bank_name']??'') ?>" required></div><div class="field"><label>Account Holder</label><input name="account_holder" value="<?= clean($pay['account_holder']??'') ?>" required></div><div class="field"><label>Account Number</label><input name="account_number" value="<?= clean($pay['account_number']??'') ?>" required></div><button>Save Payment Details</button></form></body></html>
